import React, { useMemo, useState } from "react";
import axios from "axios";
import GraphvizViewer from "./GraphvizViewer";

const STEPS = [
  {
    id: 1,
    title: "Normalized + Concat",
    description: "Spaces removed and explicit '.' concatenation inserted.",
  },
  {
    id: 2,
    title: "Postfix",
    description: "Infix regex transformed via operator precedence.",
  },
  {
    id: 3,
    title: "Thompson e-NFA",
    description: "Build epsilon-NFA using fragment composition.",
  },
  {
    id: 4,
    title: "e Removal",
    description: "Apply epsilon-closure to remove epsilon transitions.",
  },
  {
    id: 5,
    title: "Subset DFA",
    description: "Create DFA states from subsets of NFA states.",
  },
];

const QUICK_EXAMPLES = ["a", "ab", "a|b", "(a|b)*abb", "a?b*", "(ab|ba)(a|b)"];

const EDGE_CASE_HINTS = [
  "Empty input is invalid.",
  "Unbalanced parentheses are rejected.",
  "Consecutive unions like a||b are invalid.",
  "Star and optional operators must follow a symbol or ')'",
  "Use letters/digits only for symbols, operators are | + * ? ( )",
];

function buildTransitionMap(dfa) {
  const map = new Map();
  (dfa?.transitions || []).forEach(([from, symbol, to]) => {
    map.set(`${from}|${symbol}`, to);
  });
  return map;
}

function runDfaTrace(dfa, input) {
  if (!dfa?.start) {
    return {
      accepted: false,
      reason: "No DFA available yet.",
      trace: [],
      endState: null,
    };
  }

  const transitionMap = buildTransitionMap(dfa);
  let currentState = dfa.start;
  const trace = [];

  for (let i = 0; i < input.length; i += 1) {
    const symbol = input[i];
    const key = `${currentState}|${symbol}`;
    const nextState = transitionMap.get(key);

    if (!nextState) {
      trace.push({
        step: i + 1,
        from: currentState,
        symbol,
        to: "dead",
        valid: false,
      });

      return {
        accepted: false,
        reason: `No transition from ${currentState} on '${symbol}'.`,
        trace,
        endState: currentState,
      };
    }

    trace.push({
      step: i + 1,
      from: currentState,
      symbol,
      to: nextState,
      valid: true,
    });

    currentState = nextState;
  }

  const accepted = (dfa.final || []).includes(currentState);
  return {
    accepted,
    reason: accepted ? "Input ends in an accepting state." : "Input ends in a non-accepting state.",
    trace,
    endState: currentState,
  };
}

function StepPanel({ activeStep, setActiveStep, result }) {
  return (
    <section className="steps-panel card">
      <h2>Algorithm Pipeline</h2>
      <p>Click any stage to inspect data structures and graph.</p>

      <div className="steps-grid">
        {STEPS.map((step) => {
          const isActive = activeStep === step.id;
          const hasResult = !!result;

          return (
            <button
              key={step.id}
              type="button"
              className={`step-tile ${isActive ? "active" : ""} ${!hasResult ? "disabled" : ""}`}
              disabled={!hasResult}
              onClick={() => setActiveStep(step.id)}
            >
              <span className="step-badge">{step.id}</span>
              <span className="step-title">{step.title}</span>
              <span className="step-description">{step.description}</span>
            </button>
          );
        })}
      </div>
    </section>
  );
}

function TransitionTable({ transitions }) {
  if (!transitions || transitions.length === 0) {
    return <p className="empty-message">No transitions available.</p>;
  }

  return (
    <div className="table-wrap">
      <table>
        <thead>
          <tr>
            <th>From</th>
            <th>Symbol</th>
            <th>To</th>
          </tr>
        </thead>
        <tbody>
          {transitions.map(([from, symbol, to], idx) => (
            <tr key={`${from}-${symbol}-${to}-${idx}`}>
              <td>{from}</td>
              <td>{symbol}</td>
              <td>{to}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function StepDetails({ activeStep, result }) {
  if (!result) {
    return (
      <section className="card step-detail-card">
        <h2>Step Detail</h2>
        <p>Enter a regex and hit Convert to unlock detailed learning views.</p>
      </section>
    );
  }

  const currentStep = STEPS.find((s) => s.id === activeStep) || STEPS[0];

  let content = null;
  let graphData = null;

  if (activeStep === 1) {
    content = (
      <div className="text-block">
        <p>
          <strong>Input:</strong> {result.input}
        </p>
        <p>
          <strong>After explicit concatenation:</strong> {result.with_concat}
        </p>
      </div>
    );
  }

  if (activeStep === 2) {
    content = (
      <div className="text-block">
        <p>
          <strong>Postfix:</strong> {result.postfix}
        </p>
        <p>
          <strong>Alphabet:</strong> {(result.alphabet || []).join(", ") || "None"}
        </p>
      </div>
    );
  }

  if (activeStep === 3) {
    graphData = result.epsilon_nfa;
    content = <TransitionTable transitions={graphData.transitions} />;
  }

  if (activeStep === 4) {
    graphData = result.nfa;
    content = <TransitionTable transitions={graphData.transitions} />;
  }

  if (activeStep === 5) {
    graphData = result.dfa;
    content = (
      <>
        <TransitionTable transitions={graphData.transitions} />
        <div className="text-block state-set-block">
          <strong>DFA state subsets:</strong>
          {(Object.entries(result.dfa_state_sets || {})).map(([state, subset]) => (
            <p key={state}>
              {state} = {`{${subset.join(", ")}}`}
            </p>
          ))}
        </div>
      </>
    );
  }

  return (
    <section className="card step-detail-card">
      <h2>{currentStep.title}</h2>
      <p>{currentStep.description}</p>
      {content}

      {graphData && (
        <GraphvizViewer
          title={`${currentStep.title} Graph`}
          transitions={graphData.transitions}
          start={graphData.start}
          finalStates={graphData.final}
        />
      )}
    </section>
  );
}

function Simulator({ dfa }) {
  const [input, setInput] = useState("");
  const [result, setResult] = useState(null);

  const alphabet = useMemo(() => {
    return Array.from(new Set((dfa?.transitions || []).map(([, symbol]) => symbol))).sort();
  }, [dfa]);

  const onRun = () => {
    const traceResult = runDfaTrace(dfa, input.trim());
    setResult(traceResult);
  };

  if (!dfa) {
    return null;
  }

  return (
    <section className="card simulator-card">
      <h2>DFA Simulator</h2>
      <p>Try strings and inspect each transition taken by the DFA.</p>

      <div className="simulator-controls">
        <input
          value={input}
          onChange={(event) => setInput(event.target.value)}
          placeholder={`Try input over alphabet: ${alphabet.join(", ") || "-"}`}
        />
        <button type="button" onClick={onRun}>
          Run String
        </button>
      </div>

      {result && (
        <div className={`sim-output ${result.accepted ? "accepted" : "rejected"}`}>
          <p>
            <strong>{result.accepted ? "Accepted" : "Rejected"}</strong>
          </p>
          <p>{result.reason}</p>
          <p>
            End state: <strong>{result.endState || "-"}</strong>
          </p>

          {result.trace.length > 0 && (
            <div className="trace-list">
              {result.trace.map((row) => (
                <div key={`${row.step}-${row.from}-${row.symbol}`} className="trace-item">
                  <span>#{row.step}</span>
                  <span>{row.from}</span>
                  <span>--{row.symbol}--&gt;</span>
                  <span>{row.to}</span>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </section>
  );
}

function TeamSplit() {
  const tasks = [
    {
      owner: "Person 1 - Backend Core",
      items: "Parser, infix-to-postfix, Thompson construction, API contracts",
    },
    {
      owner: "Person 2 - Automata Algorithms",
      items: "Epsilon removal, subset construction, minimization extension, correctness checks",
    },
    {
      owner: "Person 3 - Visualization",
      items: "Graph rendering, state highlighting, transition table UX, graph controls",
    },
    {
      owner: "Person 4 - Learning Experience",
      items: "Step explanations, guided examples, challenge mode, glossary and hints",
    },
    {
      owner: "Person 5 - QA + Product",
      items: "Edge-case tests, API integration tests, accessibility, deployment and docs",
    },
  ];

  return (
    <section className="card team-card">
      <h2>5-Person Project Split</h2>
      <p>Parallelize development cleanly with this responsibility map.</p>

      <div className="team-grid">
        {tasks.map((task) => (
          <article key={task.owner}>
            <h3>{task.owner}</h3>
            <p>{task.items}</p>
          </article>
        ))}
      </div>
    </section>
  );
}

const RegexInputCard = () => {
  const [regex, setRegex] = useState("");
  const [activeStep, setActiveStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [result, setResult] = useState(null);

  const convert = async () => {
    setError("");
    setLoading(true);

    try {
      const response = await axios.post("http://127.0.0.1:8000/convert", { regex });
      setResult(response.data);
      setActiveStep(1);
    } catch (err) {
      const message = err?.response?.data?.detail || "Conversion failed. Check regex format.";
      setError(message);
      setResult(null);
    } finally {
      setLoading(false);
    }
  };

  const reset = () => {
    setRegex("");
    setResult(null);
    setError("");
    setActiveStep(1);
  };

  return (
    <main className="learning-shell">
      <section className="hero-card card">
        <div>
          <h1>Regex to DFA Interactive Lab</h1>
          <p>
            Learn the full pipeline from regex parsing to Thompson construction to subset DFA generation,
            with visual structures at every step.
          </p>
        </div>

        <div className="hero-input-row">
          <input
            value={regex}
            onChange={(event) => setRegex(event.target.value)}
            placeholder="Try: (a|b)*abb"
          />
          <button type="button" onClick={convert} disabled={loading}>
            {loading ? "Converting..." : "Convert"}
          </button>
          <button type="button" className="secondary" onClick={reset}>
            Reset
          </button>
        </div>

        <div className="example-row">
          {QUICK_EXAMPLES.map((item) => (
            <button key={item} type="button" className="example-chip" onClick={() => setRegex(item)}>
              {item}
            </button>
          ))}
        </div>

        {error && <p className="error-box">{error}</p>}
      </section>

      <section className="card edge-card">
        <h2>Edge-Case Rules</h2>
        <div className="edge-list">
          {EDGE_CASE_HINTS.map((hint) => (
            <p key={hint}>{hint}</p>
          ))}
        </div>
      </section>

      <StepPanel activeStep={activeStep} setActiveStep={setActiveStep} result={result} />
      <StepDetails activeStep={activeStep} result={result} />
      <Simulator dfa={result?.dfa} />
      <TeamSplit />
    </main>
  );
};

export default RegexInputCard;
